code.python:
l, r = 0, len(arr) - 1
while l <= r:
    m = (l + r) // 2
    if arr[m] == target:
        return m
    elif arr[m] < target:
        l = m + 1
    else:
        r = m - 1
return -1

code.javascript:
let l = 0, r = arr.length - 1;
while (l <= r) {
  let m = Math.floor((l + r) / 2);
  if (arr[m] === target) return m;
  if (arr[m] < target) l = m + 1;
  else r = m - 1;
}
return -1;

